A developer uses `std::cerr` to simulate watching intermediate values. What does this program print to **stdout**?

```cpp
#include <iostream>

int calc(int x, int y) {
    int a = x + y;
    std::cerr << "[watch] a=" << a << "\n";
    int b = a * x;
    std::cerr << "[watch] b=" << b << "\n";
    return b - y;
}

int main() {
    std::cout << calc(3, 2) << "\n";
    return 0;
}
```

What does this program print to **stdout**?

```cpp
#include <iostream>

int offset_product(int base, int offset) {
    std::cerr << "[watch] base*(offset-1)="
              << base * (offset - 1) << "\n";
    return base * (offset - 1);
}

int main() {
    std::cout << offset_product(6, 4) << "\n";
    return 0;
}
```
